     1→/**
     2→ * Timing drift detection and correction mechanisms
     3→ * Monitors timing precision and warns when accuracy degrades
     4→ */
     5→
     6→import { PrecisionClock, PrecisionTimestamp } from './PrecisionClock';
     7→
     8→export interface DriftMeasurement {
     9→  readonly timestamp: number;
    10→  readonly audioPerformanceDelta: number;
    11→  readonly rafPerformanceDelta: number;
    12→  readonly jitter: number;
    13→  readonly frequency: number;
    14→}
    15→
    16→export interface DriftStatus {
    17→  readonly isAccurate: boolean;
    18→  readonly maxObservedJitter: number;
    19→  readonly averageJitter: number;
    20→  readonly driftTrend: number;
    21→  readonly warnings: string[];
    22→  readonly recommendations: string[];
    23→}
    24→
    25→export class TimingDriftDetector {
    26→  private measurements: DriftMeasurement[] = [];
    27→  private warningThreshold: number = 2; // 2ms warning threshold
    28→  private criticalThreshold: number = 5; // 5ms critical threshold
    29→  private maxMeasurements: number = 1000;
    30→  private measurementInterval: number = 100; // ms between measurements
    31→  private intervalId: number | null = null;
    32→  private clock: PrecisionClock;
    33→  private lastMeasurement: number = 0;
    34→
    35→  constructor(clock: PrecisionClock) {
    36→    this.clock = clock;
    37→  }
    38→
    39→  /**
    40→   * Start continuous drift monitoring
    41→   */
    42→  startMonitoring(): void {
    43→    if (this.intervalId) {
    44→      this.stopMonitoring();
    45→    }
    46→
    47→    this.intervalId = window.setInterval(() => {
    48→      this.takeMeasurement();
    49→    }, this.measurementInterval);
    50→  }
    51→
    52→  /**
    53→   * Stop drift monitoring
    54→   */
    55→  stopMonitoring(): void {
    56→    if (this.intervalId) {
    57→      clearInterval(this.intervalId);
    58→      this.intervalId = null;
    59→    }
    60→  }
    61→
    62→  /**
    63→   * Take a single drift measurement
    64→   */
    65→  takeMeasurement(): DriftMeasurement {
    66→    const timestamp = this.clock.now();
    67→    const measurement = this.calculateDriftMeasurement(timestamp);
    68→    
    69→    this.measurements.push(measurement);
    70→    
    71→    // Keep only recent measurements
    72→    if (this.measurements.length > this.maxMeasurements) {
    73→      this.measurements.shift();
    74→    }
    75→    
    76→    return measurement;
    77→  }
    78→
    79→  /**
    80→   * Get current drift status
    81→   */
    82→  getDriftStatus(): DriftStatus {
    83→    if (this.measurements.length < 10) {
    84→      return {
    85→        isAccurate: true,
    86→        maxObservedJitter: 0,
    87→        averageJitter: 0,
    88→        driftTrend: 0,
    89→        warnings: ['Insufficient measurements for drift analysis'],
    90→        recommendations: ['Continue monitoring to gather baseline data']
    91→      };
    92→    }
    93→
    94→    const recentMeasurements = this.measurements.slice(-100);
    95→    const jitters = recentMeasurements.map(m => m.jitter);
    96→    const maxJitter = Math.max(...jitters);
    97→    const averageJitter = jitters.reduce((a, b) => a + b, 0) / jitters.length;
    98→    const driftTrend = this.calculateDriftTrend();
    99→
   100→    const warnings: string[] = [];
   101→    const recommendations: string[] = [];
   102→
   103→    // Check for accuracy issues
   104→    if (maxJitter > this.criticalThreshold) {
   105→      warnings.push(`Critical timing jitter detected: ${maxJitter.toFixed(2)}ms`);
   106→      recommendations.push('Consider reducing system load or switching to dedicated timing hardware');
   107→    } else if (maxJitter > this.warningThreshold) {
   108→      warnings.push(`High timing jitter detected: ${maxJitter.toFixed(2)}ms`);
   109→      recommendations.push('Monitor system performance and close unnecessary applications');
   110→    }
   111→
   112→    // Check for drift trend
   113→    if (Math.abs(driftTrend) > 0.1) {
   114→      warnings.push(`Timing drift trend detected: ${driftTrend.toFixed(3)}ms/s`);
   115→      recommendations.push('System clock may be unstable - consider calibration');
   116→    }
   117→
   118→    return {
   119→      isAccurate: maxJitter <= this.warningThreshold,
   120→      maxObservedJitter: maxJitter,
   121→      averageJitter,
   122→      driftTrend,
   123→      warnings,
   124→      recommendations
   125→    };
   126→  }
   127→
   128→  /**
   129→   * Get detailed measurement history
   130→   */
   131→  getMeasurementHistory(): DriftMeasurement[] {
   132→    return [...this.measurements];
   133→  }
   134→
   135→  /**
   136→   * Reset measurement history
   137→   */
   138→  reset(): void {
   139→    this.measurements = [];
   140→    this.lastMeasurement = 0;
   141→  }
