      if (!this.clock || !this.scheduler || !this.deviceManager) { // Add check
        throw new Error('Experiment not properly initialized');
      }

      return {
        clock: this.clock,
        scheduler: this.scheduler,
        deviceManager: this.deviceManager, // Add deviceManager
        data: { /* ... */ },
      };
    }

    // Update run method to initialize DeviceManager
    async run(participantId?: string): Promise<ExperimentData> {
      // ...
      const { DeviceManager } = await import('@psyforge/devices');
      this.clock = new PrecisionClock();
      this.scheduler = createScheduler(this.clock);
      this.deviceManager = new DeviceManager(this.clock); // Create it
      await this.deviceManager.initialize(); // Initialize it
      // ...
    }
